import{bQ as s,aL as a,u as e,G as i}from"./chunks/framework.D06dwy5q.js";const k=JSON.parse('{"title":"监控平台运维","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/25-监控平台运维.md","filePath":"12.可观测性与监控告警/25-监控平台运维.md","lastUpdated":null}'),d={name:"12.可观测性与监控告警/25-监控平台运维.md"};function r(n,t,h,l,p,o){return a(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="监控平台运维" tabindex="-1">监控平台运维 <a class="header-anchor" href="#监控平台运维" aria-label="Permalink to &quot;监控平台运维&quot;">​</a></h1><p>监控平台本身也要被运维。Prometheus 能采到业务指标，不代表平台长期稳定；采集目标变多、标签基数变大、保留周期变长、规则越来越多以后，Prometheus、Alertmanager、Grafana 都会出现容量、性能和可用性问题。监控平台出故障时，最尴尬的是业务已经异常，但告警没有发出来。</p><h2 id="一、平台自身要监控" tabindex="-1">一、平台自身要监控 <a class="header-anchor" href="#一、平台自身要监控" aria-label="Permalink to &quot;一、平台自身要监控&quot;">​</a></h2><p>Prometheus 自己会暴露 <code>/metrics</code>。当前实验环境里已经把 Prometheus 自身作为一个 target：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">scrape_configs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">job_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">prometheus</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    static_configs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">127.0.0.1:9090</span></span></code></pre></div><p>常见自监控指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td><code>prometheus_target_interval_length_seconds</code></td><td>实际抓取间隔分布</td></tr><tr><td><code>prometheus_target_scrapes_exceeded_sample_limit_total</code></td><td>超过样本限制次数</td></tr><tr><td><code>prometheus_rule_evaluation_duration_seconds</code></td><td>规则计算耗时</td></tr><tr><td><code>prometheus_rule_group_last_duration_seconds</code></td><td>规则组最近一次计算耗时</td></tr><tr><td><code>prometheus_tsdb_head_series</code></td><td>当前 head 中序列数量</td></tr><tr><td><code>prometheus_tsdb_wal_corruptions_total</code></td><td>WAL 损坏次数</td></tr><tr><td><code>prometheus_notifications_errors_total</code></td><td>发送告警失败次数</td></tr><tr><td><code>alertmanager_notifications_failed_total</code></td><td>Alertmanager 通知失败次数</td></tr></tbody></table><p>监控平台自己至少留一个小看板：target 数、down 数、TSDB series 数、规则计算耗时、磁盘使用、Alertmanager 通知失败。业务看板再漂亮，平台自身不稳也白搭。</p><h2 id="二、容量和保留周期" tabindex="-1">二、容量和保留周期 <a class="header-anchor" href="#二、容量和保留周期" aria-label="Permalink to &quot;二、容量和保留周期&quot;">​</a></h2><p>Prometheus 本地 TSDB 的压力主要来自三件事：序列数量、采集频率、保留周期。</p><table tabindex="0"><thead><tr><th>因素</th><th>影响</th></tr></thead><tbody><tr><td>target 数</td><td>目标越多，抓取越多</td></tr><tr><td>每个 target 样本数</td><td>Exporter 暴露指标越多，写入越多</td></tr><tr><td>label 基数</td><td>序列数量膨胀</td></tr><tr><td>scrape interval</td><td>间隔越短，样本越多</td></tr><tr><td>retention</td><td>保留越久，磁盘越大</td></tr></tbody></table><p>启动参数里可以设置保留时间和数据目录：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ExecStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/opt/prometheus/prometheus \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  --</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">config.file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/etc/prometheus/prometheus.yml \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  --</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">storage.tsdb.path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/var/lib/prometheus \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  --</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">storage.tsdb.retention.time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=15d \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  --</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">web.listen-address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=:9090 \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  --web.enable-lifecycle</span></span></code></pre></div><p>实验环境保留 7 到 15 天通常够用。生产环境要按指标量和回溯需求计算；如果需要保留几个月甚至一年，更适合接 Thanos、Mimir、VictoriaMetrics 这类远端存储或长期存储方案。</p><h2 id="三、远端存储和-victoriametrics" tabindex="-1">三、远端存储和 VictoriaMetrics <a class="header-anchor" href="#三、远端存储和-victoriametrics" aria-label="Permalink to &quot;三、远端存储和 VictoriaMetrics&quot;">​</a></h2><p>Prometheus 本地 TSDB 适合保存短期指标。需要保存几个月甚至一年以上、多个 Prometheus 实例汇总查询、或者高基数指标较多时，本地 TSDB 的磁盘和查询压力会变得明显。VictoriaMetrics 兼容 Prometheus 查询接口和 <code>remote_write</code> 协议，可以作为远端存储，也可以被 Grafana、Nightingale 这类平台按 PromQL 数据源接入。</p><p>常见链路：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20prom1%5B%22Prometheus%20A%3Cbr%2F%3E%E7%9F%AD%E6%9C%9F%E5%AD%98%E5%82%A8%22%5D%20--%3E%20vm%5B%22VictoriaMetrics%3Cbr%2F%3E%E9%95%BF%E6%9C%9F%E5%AD%98%E5%82%A8%20%2F%20%E6%B1%87%E6%80%BB%E6%9F%A5%E8%AF%A2%22%5D%0A%20%20%20%20prom2%5B%22Prometheus%20B%3Cbr%2F%3E%E7%9F%AD%E6%9C%9F%E5%AD%98%E5%82%A8%22%5D%20--%3E%20vm%0A%20%20%20%20categraf%5B%22Categraf%20%2F%20%E5%85%B6%E4%BB%96%E9%87%87%E9%9B%86%E5%99%A8%22%5D%20--%3E%20vm%0A%20%20%20%20vm%20--%3E%20grafana%5B%22Grafana%3Cbr%2F%3EPromQL%20%E6%9F%A5%E8%AF%A2%22%5D%0A%20%20%20%20vm%20--%3E%20n9e%5B%22Nightingale%3Cbr%2F%3EPromQL%20%E6%9F%A5%E8%AF%A2%22%5D%0A"></div><p>Prometheus 写入 VictoriaMetrics：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">remote_write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://127.0.0.1:8428/api/v1/write</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Prometheus 本地保留短期数据，VictoriaMetrics 侧按自己的保留周期保存长期数据</span></span></code></pre></div><p>VictoriaMetrics 单节点版本常用于中小规模或实验环境，一个二进制同时承担写入、查询和存储。集群版本会拆成 <code>vminsert</code>、<code>vmselect</code>、<code>vmstorage</code>，适合多 Prometheus 汇总、跨机房和更大规模的长期存储。</p><table tabindex="0"><thead><tr><th>组件</th><th>作用</th></tr></thead><tbody><tr><td><code>vminsert</code></td><td>写入入口，接收 remote_write</td></tr><tr><td><code>vmselect</code></td><td>查询入口，对外提供 PromQL 查询</td></tr><tr><td><code>vmstorage</code></td><td>存储节点，保存时序数据</td></tr><tr><td><code>vmalert</code></td><td>告警规则计算，可选</td></tr></tbody></table><p>远端存储不是“把 Prometheus 磁盘问题丢给另一个服务”。保留周期、标签基数、查询范围、磁盘容量和备份策略仍然要单独设计。Nightingale 接入 VictoriaMetrics 时，页面上常写成 <code>Prometheus Like</code> 数据源，含义是兼容 Prometheus 查询协议，不代表后端必须是原生 Prometheus。</p><h2 id="四、标签基数治理" tabindex="-1">四、标签基数治理 <a class="header-anchor" href="#四、标签基数治理" aria-label="Permalink to &quot;四、标签基数治理&quot;">​</a></h2><p>标签基数是 Prometheus 最常见的隐性风险。一个指标如果带上 <code>user_id</code>、<code>request_id</code>、<code>trace_id</code>、订单号，序列数量会快速膨胀。</p><p>排查高基数可以从这些方向看：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 当前 head 中活跃序列数量</span></span>
<span class="line"><span>prometheus_tsdb_head_series</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 按 job 粗略统计 up 序列数量</span></span>
<span class="line"><span>count by (job) (up)</span></span></code></pre></div><p>更细的高基数分析通常要用 Prometheus 自带 TSDB 工具或管理 API。原则很简单：稳定维度适合标签，唯一 ID 不适合标签。</p><table tabindex="0"><thead><tr><th>适合标签</th><th>不适合标签</th></tr></thead><tbody><tr><td><code>service</code>、<code>env</code>、<code>cluster</code>、<code>instance</code>、<code>status</code></td><td><code>user_id</code>、<code>request_id</code>、<code>trace_id</code>、订单号、错误堆栈</td></tr></tbody></table><p>TraceID 要放到链路和日志里。指标上要关联 Trace，可以用 exemplar，不是把 TraceID 变成普通 label。</p><h2 id="五、采集异常" tabindex="-1">五、采集异常 <a class="header-anchor" href="#五、采集异常" aria-label="Permalink to &quot;五、采集异常&quot;">​</a></h2><p>Targets 页面是采集异常第一入口。常见状态：</p><p>页面路径：</p><p><code>Status -&gt; Target health</code> （中文：状态 -&gt; 目标健康状态）</p><p>操作上先按 scrape pool 过滤，再展开异常 target。<code>Last scrape</code> 能看到最近一次抓取时间和耗时，<code>State</code> 能看到 <code>UP</code> 或 <code>DOWN</code>，展开后能看到最近错误原因。</p><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th></tr></thead><tbody><tr><td><code>DOWN</code></td><td>exporter 挂了、端口不通、防火墙、地址写错</td></tr><tr><td><code>context deadline exceeded</code></td><td>网络慢、服务响应慢、采集超时</td></tr><tr><td><code>server returned HTTP status</code></td><td>抓到了错误页面或鉴权失败</td></tr><tr><td><code>sample limit exceeded</code></td><td>单个 target 样本太多</td></tr><tr><td><code>label limit exceeded</code></td><td>标签数量或长度超过限制</td></tr></tbody></table><p>排查顺序：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Prometheus 机器上访问 target，验证网络和 exporter</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://192.168.10.13:9100/metrics</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看 Prometheus 配置是否能解析</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/opt/prometheus/promtool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/prometheus/prometheus.yml</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># reload 后看服务日志，抓取错误通常会写出来</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prometheus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span></code></pre></div><p>如果 Grafana 面板没数据，先回 Prometheus 查同一条 PromQL，再看 Targets。Grafana 在这条链路里是查询入口，不是采集入口。</p><h2 id="六、规则和告警噪声" tabindex="-1">六、规则和告警噪声 <a class="header-anchor" href="#六、规则和告警噪声" aria-label="Permalink to &quot;六、规则和告警噪声&quot;">​</a></h2><p>规则文件变多以后，要关注规则计算耗时。规则计算时间接近或超过 <code>evaluation_interval</code>，告警就会延迟，甚至影响 Prometheus 整体性能。</p><p>规则检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 检查所有规则文件语法</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/opt/prometheus/promtool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/prometheus/rules/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.yml</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 检查主配置，能同时发现 rule_files 路径问题</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/opt/prometheus/promtool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/prometheus/prometheus.yml</span></span></code></pre></div><p>告警噪声常见来源：</p><table tabindex="0"><thead><tr><th>来源</th><th>处理方向</th></tr></thead><tbody><tr><td>阈值太敏感</td><td>加 <code>for</code>，按业务基线调阈值</td></tr><tr><td>缺少分组</td><td>调整 Alertmanager <code>group_by</code></td></tr><tr><td>派生告警太多</td><td>用抑制规则</td></tr><tr><td>维护窗口告警</td><td>用静默，和变更记录对应</td></tr><tr><td>低价值告警太多</td><td>降级到看板或日志</td></tr></tbody></table><p>告警规则不是越多越好。值班的人看到一堆已知噪声时，会很自然地忽略通知，真正的异常也容易被盖住。</p><h2 id="七、alertmanager-运维" tabindex="-1">七、Alertmanager 运维 <a class="header-anchor" href="#七、alertmanager-运维" aria-label="Permalink to &quot;七、Alertmanager 运维&quot;">​</a></h2><p>Alertmanager 重点看三类问题：是否收到 Prometheus 告警，是否正确分组/静默/抑制，是否成功发出通知。</p><p>页面入口：</p><table tabindex="0"><thead><tr><th>入口</th><th>用途</th></tr></thead><tbody><tr><td><code>Alerts</code>（中文：告警）</td><td>查看当前进入 Alertmanager 的告警、labels 和 receiver</td></tr><tr><td><code>Silences</code>（中文：静默）</td><td>查看维护窗口或临时屏蔽规则</td></tr><tr><td><code>Status</code>（中文：状态）</td><td>查看实际生效配置、集群状态和 receiver</td></tr></tbody></table><p>检查入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Alertmanager ready</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:9093/-/ready</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看当前状态和集群信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:9093/api/v2/status</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看最近日志，通知失败、配置错误会出现在这里</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> alertmanager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span></code></pre></div><p>生产里 Alertmanager 通常至少两个副本。单节点 Alertmanager 挂掉时，Prometheus 仍然能计算告警，但通知链路会断。</p><h2 id="八、grafana-运维" tabindex="-1">八、Grafana 运维 <a class="header-anchor" href="#八、grafana-运维" aria-label="Permalink to &quot;八、Grafana 运维&quot;">​</a></h2><p>Grafana 侧重点不是采集，而是数据源、看板、权限和告警查询。</p><p>页面入口：</p><table tabindex="0"><thead><tr><th>入口</th><th>用途</th></tr></thead><tbody><tr><td><code>Connections -&gt; Data sources</code>（中文：连接 -&gt; 数据源）</td><td>检查 Prometheus URL、认证和 Save &amp; test</td></tr><tr><td><code>Explore</code>（中文：探索）</td><td>临时执行 PromQL，判断数据源是否能查到数据</td></tr><tr><td><code>Dashboards -&gt; Dashboard -&gt; Panel menu -&gt; Edit</code>（中文：仪表盘 -&gt; 看板 -&gt; 面板菜单 -&gt; 编辑）</td><td>检查面板查询、变量、单位和时间范围</td></tr><tr><td><code>Administration</code>（中文：管理）</td><td>检查用户、组织、权限和插件</td></tr></tbody></table><table tabindex="0"><thead><tr><th>检查点</th><th>说明</th></tr></thead><tbody><tr><td>数据源</td><td>Prometheus URL、鉴权、默认数据源</td></tr><tr><td>看板</td><td>变量、时间范围、PromQL、面板单位</td></tr><tr><td>权限</td><td>组织、用户、文件夹权限</td></tr><tr><td>provisioning</td><td>数据源和看板是否由配置管理</td></tr><tr><td>插件</td><td>插件版本、兼容性、安全风险</td></tr></tbody></table><p>Grafana 看板最好能配置化。手工在页面改出来的看板，如果没有导出 JSON 或放进版本管理，重装平台时很容易丢。</p><h2 id="九、备份和迁移" tabindex="-1">九、备份和迁移 <a class="header-anchor" href="#九、备份和迁移" aria-label="Permalink to &quot;九、备份和迁移&quot;">​</a></h2><p>监控平台至少要备份这些东西：</p><table tabindex="0"><thead><tr><th>对象</th><th>内容</th></tr></thead><tbody><tr><td>Prometheus 配置</td><td><code>prometheus.yml</code>、rules、file_sd 文件</td></tr><tr><td>Alertmanager 配置</td><td><code>alertmanager.yml</code>、通知模板</td></tr><tr><td>Grafana 数据</td><td>dashboard、datasource、用户权限</td></tr><tr><td>部署文件</td><td>systemd unit、容器编排文件、Helm values</td></tr><tr><td>运行数据</td><td>是否备份 TSDB 要看保留需求</td></tr></tbody></table><p>Prometheus TSDB 一般不作为最优先备份对象，除非有审计或历史回溯要求。配置、规则、看板、通知模板更应该先纳入版本管理。</p><h2 id="十、平台故障场景" tabindex="-1">十、平台故障场景 <a class="header-anchor" href="#十、平台故障场景" aria-label="Permalink to &quot;十、平台故障场景&quot;">​</a></h2><p>常见故障：</p><table tabindex="0"><thead><tr><th>场景</th><th>处理方向</th></tr></thead><tbody><tr><td>Prometheus 启动失败</td><td>配置语法、规则文件、数据目录权限</td></tr><tr><td>Prometheus 磁盘满</td><td>缩短保留、清理旧 block、扩容磁盘</td></tr><tr><td>Targets 大面积 down</td><td>网络、DNS、服务发现、Prometheus 自身网络</td></tr><tr><td>查询很慢</td><td>高基数、时间范围太大、PromQL 太重</td></tr><tr><td>告警没发</td><td>Prometheus 到 Alertmanager、路由、receiver</td></tr><tr><td>Grafana 没数据</td><td>数据源、时间范围、PromQL、Prometheus 状态</td></tr></tbody></table><p>监控平台变更也要有窗口。改采集配置、改保留周期、批量加 target、导入大量规则，都会影响 Prometheus。变更前先在测试环境检查规则和样本量，再推到生产。</p>`,67)])])}const g=s(d,[["render",r]]);export{k as __pageData,g as default};
